def fizzbuzz(n):
    """
    Returns the classic FizzBuzz sequence as a list of strings for inputs 1 through n inclusive.
    """
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return result
